 * ================================================= */
void example_prodcons(void) {
    sem_t *e = sem_open("/kf_ex_e", O_CREAT|O_EXCL, 0644, 1);
    sem_t *f = sem_open("/kf_ex_f", O_CREAT|O_EXCL, 0644, 0);
    char msg[32] = {0};
    /* produce */ sem_wait(e); strcpy(msg, "hello"); sem_post(f);
    /* consume */ sem_wait(f); printf("Got: %s\n", msg); sem_post(e);
    sem_close(e); sem_close(f);
    sem_unlink("/kf_ex_e"); sem_unlink("/kf_ex_f");
